const express = require('express');
const router = express.Router();

// Mock database - replace with real database in production
const users = new Map();
let idCounter = 1;

// Validation helper function
const validateUserInput = (data, isUpdate = false) => {
  const errors = [];

  if (!isUpdate) {
    // Required fields for creation
    if (!data.email) {
      errors.push('Email is required');
    } else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(data.email)) {
      errors.push('Invalid email format');
    }

    if (!data.password) {
      errors.push('Password is required');
    } else if (data.password.length < 8) {
      errors.push('Password must be at least 8 characters long');
    }

    if (!data.name) {
      errors.push('Name is required');
    } else if (data.name.trim().length < 2) {
      errors.push('Name must be at least 2 characters long');
    }
  } else {
    // Optional validation for updates
    if (data.email && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(data.email)) {
      errors.push('Invalid email format');
    }

    if (data.password && data.password.length < 8) {
      errors.push('Password must be at least 8 characters long');
    }

    if (data.name && data.name.trim().length < 2) {
      errors.push('Name must be at least 2 characters long');
    }
  }

  return errors;
};

// Helper to sanitize user response (remove sensitive data)
const sanitizeUser = (user) => {
  const { password, ...safeUser } = user;
  return safeUser;
};

// POST /api/users - Create a new user
router.post('/', async (req, res, next) => {
  try {
    const { email, password, name } = req.body;

    // Validate input
    const validationErrors = validateUserInput(req.body);
    if (validationErrors.length > 0) {
      return res.status(400).json({
        success: false,
        error: 'Validation failed',
        details: validationErrors
      });
    }

    // Check for duplicate email
    const existingUser = Array.from(users.values()).find(
      user => user.email.toLowerCase() === email.toLowerCase()
    );
    if (existingUser) {
      return res.status(409).json({
        success: false,
        error: 'User with this email already exists'
      });
    }

    // Create user (in real app, hash the password!)
    const newUser = {
      id: idCounter++,
      email: email.toLowerCase().trim(),
      password: password, // Should be hashed in production
      name: name.trim(),
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString()
    };

    users.set(newUser.id, newUser);

    res.status(201).json({
      success: true,
      data: sanitizeUser(newUser)
    });
  } catch (error) {
    next(error);
  }
});

// GET /api/users - Get all users (with optional filtering)
router.get('/', async (req, res, next) => {
  try {
    const { name, email } = req.query;
    let result = Array.from(users.values());

    // Apply filters if provided
    if (name) {
      result = result.filter(user => 
        user.name.toLowerCase().includes(name.toLowerCase())
      );
    }

    if (email) {
      result = result.filter(user => 
        user.email.toLowerCase().includes(email.toLowerCase())
      );
    }

    res.json({
      success: true,
      count: result.length,
      data: result.map(sanitizeUser)
    });
  } catch (error) {
    next(error);
  }
});

// GET /api/users/:id - Get a single user by ID
router.get('/:id', async (req, res, next) => {
  try {
    const userId = parseInt(req.params.id, 10);

    if (isNaN(userId)) {
      return res.status(400).json({
        success: false,
        error: 'Invalid user ID format'
      });
    }

    const user = users.get(userId);

    if (!user) {
      return res.status(404).json({
        success: false,
        error: 'User not found'
      });
    }

    res.json({
      success: true,
      data: sanitizeUser(user)
    });
  } catch (error) {
    next(error);
  }
});

// PUT /api/users/:id - Update a user
router.put('/:id', async (req, res, next) => {
  try {
    const userId = parseInt(req.params.id, 10);

    if (isNaN(userId)) {
      return res.status(400).json({
        success: false,
        error: 'Invalid user ID format'
      });
    }

    const user = users.get(userId);

    if (!user) {
      return res.status(404).json({
        success: false,
        error: 'User not found'
      });
    }

    // Validate update input
    const validationErrors = validateUserInput(req.body, true);
    if (validationErrors.length > 0) {
      return res.status(400).json({
        success: false,
        error: 'Validation failed',
        details: validationErrors
      });
    }

    // Check for duplicate email if email is being updated
    if (req.body.email) {
      const existingUser = Array.from(users.values()).find(
        u => u.id !== userId && 
             u.email.toLowerCase() === req.body.email.toLowerCase()
      );
      if (existingUser) {
        return res.status(409).json({
          success: false,
          error: 'Email already in use by another user'
        });
      }
    }

    // Update user fields
    const updatedUser = {
      ...user,
      ...(req.body.email && { email: req.body.email.toLowerCase().trim() }),
      ...(req.body.password && { password: req.body.password }),
      ...(req.body.name && { name: req.body.name.trim() }),
      updatedAt: new Date().toISOString()
    };

    users.set(userId, updatedUser);

    res.json({
      success: true,
      data: sanitizeUser(updatedUser)
    });
  } catch (error) {
    next(error);
  }
});

// DELETE /api/users/:id - Delete a user
router.delete('/:id', async (req, res, next) => {
  try {
    const userId = parseInt(req.params.id, 10);

    if (isNaN(userId)) {
      return res.status(400).json({
        success: false,
        error: 'Invalid user ID format'
      });
    }

    if (!users.has(userId)) {
      return res.status(404).json({
        success: false,
        error: 'User not found'
      });
    }

    users.delete(userId);

    res.json({
      success: true,
      message: 'User deleted successfully'
    });
  } catch (error) {
    next(error);
  }
});

module.exports = router;
```

